siblePerson\", \"type\": \"text\", \"label\": \"本公司商务负责人\", \"autoFill\": \"businessResponsibleName\", \"readOnly\": true, \"required\": false, \"editablePart\": \"business\"}, {\"key\": \"projectResponsibleContact\", \"type\": \"text\", \"label\": \"联系方式\", \"required\": false, \"editablePart\": \"business\"}], \"editablePart\": \"business\"}, {\"key\": \"projectExecutionModeSection\", \"title\": \"项目开展模式\", \"fields\": [{\"key\": \"projectExecutionMode\", \"type\": \"select\", \"label\": \"项目开展模式\", \"options\": [\"自研模式\", \"供应链模式\"], \"required\": true, \"description\": \"仅用于生成 1.2 项目立项审批表，不关联系统项目模式。\", \"editablePart\": \"business\"}], \"editablePart\": \"business\"}], \"documentCode\": \"1.2\", \"documentName\": \"项目立项审批表\", \"scoringSections\": [{\"key\": \"businessModule\", \"items\": [{\"key\": \"customerEnterpriseAttribute\", \"itemName\": \"客户企业属性\", \"clauseContent\": \"客户企业属性\", \"evaluationStandard\": \"0-以上均不是；1-行业龙头企业；2-国企；3-央企；4-军工企业；5-上市公司\", \"informationCollectionNotes\": \"\"}, {\"key\": \"projectSource\", \"itemName\": \"项目来源\", \"clauseContent\": \"项目来源\", \"evaluationStandard\": \"0-挂网信息；1-多层分包项目；2-分包项目；3-中间人提供；4-客户主动联系；5-公司人脉\", \"informationCollectionNotes\": \"\"}, {\"key\": \"projectPositioning\", \"itemName\": \"项目定位\", \"clauseContent\": \"项目定位\", \"evaluationStandard\": \"0-无明确定位；1-降低成本；2-增加效率；3-辅助设备替换；4-关键设备替换；5-新建必需设备\", \"informationCollectionNotes\": \"\"}, {\"key\": \"businessCompetitionCondition\", \"itemName\": \"商务竞争条件\", \"clauseContent\": \"商务竞争条件\", \"evaluationStandard\": \"0-公开招标，低价中标；1-公开招标，综合评分；2-邀请招标，低价中标；3-邀请招标，综合评分；4-多家竞争性谈判；5-独家\", \"informationCollectionNotes\": \"\"}, {\"key\": \"projectBudget\", \"itemName\": \"项目预算\", \"clauseContent\": \"项目预算\", \"evaluationStandard\": \"0-无预算；1-预算不足；2-预算刚好，项目地点在外地；3-预算刚好，项目地点在重庆；4-预算充足，项目地点在外地；5-预算充足，项目地点在重庆\", \"informationCollectionNotes\": \"\"}, {\"key\": \"paymentCondition\", \"itemName\": \"付款条件\", \"clauseContent\": \"付款条件\", \"evaluationStandard\": \"0-低于模板比例或无预付款；1-预付≥10%，发货付款至全款比例≥50%；2-预付≥20%，发货付款至全款比例≥50%；3-预付≥20%，发货付款至全款比例≥60%；4-预付≥30%，发货付款至全款比例≥70%；5-预付≥30%，发货付款至全款比例≥90%\", \"informationCollectionNotes\": \"\"}], \"title\": \"商务模块\", \"editablePart\": \"business\"}, {\"key\": \"technicalModule\", \"items\": [{\"key\": \"projectRequirement\", \"itemName\": \"项目需求\", \"clauseContent\": \"项目需求\", \"evaluationStandard\": \"0-无项目需求；1-需求模糊，无数据支撑；2-需求模糊，有数据支撑；3-需求明确，但无数据支撑；4-需求明确，有数据支撑；5-有目标方案文件\", \"informationCollectionNotes\": \"\"}, {\"key\": \"specialEnvironment\", \"itemName\": \"特殊环境要求\", \"clauseContent\": \"特殊环境要求（防爆/高温/高湿/高压/高海拔/特殊防腐/低噪音）\", \"evaluationStandard\": \"0-以上要求5点及以上；1-以上要求4点；2-以上要求3点；3-以上要求2点；4-以上要求1点；5-以上要求均无\", \"informationCollectionNotes\": \"\"}, {\"key\": \"industryThreshold\", \"itemName\": \"行业门槛\", \"clauseContent\": \"行业门槛\", \"evaluationStandard\": \"0-3体系+基本国标+行业标准+企业标准+特殊标准；1-3体系+基本国标+行业标准+企业标准；2-3体系+基本国标+行业标准；3-3体系+基本国标；4-只要求3体系；5-无行业门槛\", \"informationCollectionNotes\": \"\"}, {\"key\": \"technologyMaturity\", \"itemName\": \"技术成熟度\", \"clauseContent\": \"技术成熟度\", \"evaluationStandard\": \"0-无相关技术可查；1-只有技术概念；2-可以看到原型机；3-小范围用户使用；4-已经市场推广；5-本公司工程师工作经历相符\", \"informationCollectionNotes\": \"\"}, {\"key\": \"rdMode\", \"itemName\": \"研发模式\", \"clauseContent\": \"研发模式\", \"evaluationStandard\": \"0-市场上无相关供应商；1-市场上只有个别相关产品；2-市场上有少量相关产品；3-市场上有大量相关产品；4-合作供应商有相关产品；5-本公司有相关产品\", \"informationCollectionNotes\": \"\"}], \"title\": \"技术模块\", \"editablePart\": \"technical\"}], \"templateFileName\": \"项目立项审批表-模板.xlsx\", \"reviewOpinionSource\": \"initiationReviewNodes\"}', '{\"projectName\": \"Test_0714\", \"rdModeScore\": \"3\", \"customerName\": \"TTTT\", \"_collaboration\": {\"businessSubmitted\": false, \"technicalSubmitted\": false, \"businessSubmittedAt\": null, \"technicalSubmittedAt\": null, \"businessSubmittedByUserId\": null, \"technicalSubmittedByUserId\": null}, \"customerContact\": \"3695826\", \"projectBudgetScore\": \"4\", \"projectSourceScore\": \"4\", \"projectExecutionMode\": \"自研模式\", \"cust